   176→void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onEvent(Network::ConnectionEvent event) {
   177→  if (event == Network::ConnectionEvent::RemoteClose ||
   178→      event == Network::ConnectionEvent::LocalClose) {
   179→    // For the raw disconnect event, we are either between intervals in which case we already have
   180→    // a timer setup, or we did the close or got a reset, in which case we already setup a new
   181→    // timer. There is nothing to do here other than blow away the client.
   182→    parent_.dispatcher_.deferredDelete(std::move(client_));
