   300→bool GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::isHealthCheckSucceeded(
   301→    Grpc::Status::GrpcStatus grpc_status) const {
   302→  if (grpc_status != Grpc::Status::WellKnownGrpcStatus::Ok) {
   303→    return false;
   304→  }
   305→
   306→  if (!health_check_response_ ||
   307→      health_check_response_->status() != grpc::health::v1::HealthCheckResponse::SERVING) {
   308→    return false;
   309→  }
   310→
   311→  return true;
   312→}
