   314→void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onRpcComplete(
   315→    Grpc::Status::GrpcStatus grpc_status, const std::string& grpc_message, bool end_stream) {
   316→  logHealthCheckStatus(grpc_status, grpc_message);
   317→  if (isHealthCheckSucceeded(grpc_status)) {
   318→    handleSuccess(false);
   319→  } else {
   320→    handleFailure(envoy::data::core::v3::ACTIVE);
   321→  }
   322→
   323→  // Read the value as we may call resetState() and clear it.
   324→  const bool goaway = received_no_error_goaway_;
   325→
   326→  // |end_stream| will be false if we decided to stop healthcheck before HTTP stream has ended -
   327→  // invalid gRPC payload, unexpected message stream or wrong content-type.
   328→  if (end_stream) {
   329→    resetState();
   330→  } else {
   331→    // request_encoder_ can already be destroyed if the host was removed during the failure callback
   332→    // above.
   333→    if (request_encoder_ != nullptr) {
   334→      // resetState() will be called by onResetStream().
   335→      expect_reset_ = true;
   336→      request_encoder_->getStream().resetStream(Http::StreamResetReason::LocalReset);
   337→    }
   338→  }
   339→
   340→  // client_ can already be destroyed if the host was removed during the failure callback above.
   341→  if (client_ != nullptr && (!parent_.reuse_connection_ || goaway)) {
   342→    client_->close(Network::ConnectionCloseType::Abort);
   343→  }
   344→}
