   354→void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onTimeout() {
   355→  ENVOY_CONN_LOG(debug, "connection/stream timeout health_flags={}", *client_,
   356→                 HostUtility::healthFlagsToString(*host_));
   357→  expect_reset_ = true;
   358→  if (received_no_error_goaway_ || !parent_.reuse_connection_) {
   359→    client_->close(Network::ConnectionCloseType::Abort);
   360→  } else {
   361→    request_encoder_->getStream().resetStream(Http::StreamResetReason::LocalReset);
   362→  }
   363→}
